powershell -Command "
\$vs_paths = @(
    'C:\Program Files\Microsoft Visual Studio\2022\Community\MSBuild\Current\Bin\MSBuild.exe',
    'C:\Program Files (x86)\Microsoft Visual Studio\2019\Community\MSBuild\Current\Bin\MSBuild.exe',
    'C:\Program Files\Microsoft Visual Studio\2022\Enterprise\MSBuild\Current\Bin\MSBuild.exe',
    'C:\Program Files (x86)\Microsoft Visual Studio\2019\Enterprise\MSBuild\Current\Bin\MSBuild.exe'
)
foreach (\$path in \$vs_paths) {
    if (Test-Path \$path) {
        Write-Host \$path
        exit 0
    }
}
"

powershell -Command "
\$msbuild = &'C:\Program Files (x86)\Microsoft Visual Studio\Installer\vswhere.exe' -latest -products '*' -find 'MSBuild\Current\Bin\MSBuild.exe' | Select-Object -First 1
if (\$msbuild) {
    Write-Host \$msbuild
} else {
    Write-Error 'MSBuild not found'
    exit 1
}
"

powershell -Command "
\$projectDir = 'C:\Users\Administrator\Desktop\daeil_sw\작동력 검사기 3P'
\$packagesDir = Join-Path \$projectDir 'packages'

# packages 폴더 존재 확인
if (Test-Path \$packagesDir) {
    Write-Host 'packages 폴더 존재'
    Get-ChildItem \$packagesDir | Select-Object -First 5
} else {
    Write-Host 'packages 폴더 없음'
}

# packages.config 확인
\$packagesConfig = Join-Path \$projectDir 'packages.config'
if (Test-Path \$packagesConfig) {
    Write-Host 'packages.config 파일 존재'
    Select-String -Path \$packagesConfig -Pattern 'ZedGraph|ScottPlot'
}
"
